definition.script:
pipeline {
    agent any

    parameters {
        booleanParam(name: 'Include_Genomic_Data', defaultValue: true,
                     description: 'If set to true genomic data must be present or HPDS will fail to start.')
        booleanParam(name: 'VARIANT_EXPLORER', defaultValue: true,
                     description: 'Enable the variant explorer. Only enable if HPDS has been loaded with Genomic data.')
        booleanParam(name: 'ENABLE_GENE_QUERY', defaultValue: true,
                     description: 'Enable the genomic filtering UI which guides users creating genomic queries.')
        booleanParam(name: 'ENABLE_SNP_QUERY', defaultValue: true,
                     description: 'Enable the genomic filtering UI which guides users creating genomic SNP queries.')
        choice(name: 'VARIANT_EXPLORER_TYPE', choices: ['aggregate', 'full'],
               description: 'Aggregate is recommended.')
        string(name: 'EXPLORER_MAX_COUNT', defaultValue: '10000',
               description: 'Max amount of data points for the variant explorer.')
        string(name: 'VARIANT_EXPLORER_EXCLUDE_COLUMNS', defaultValue: '',
               description: 'Advanced: An array of columns to exclude in the variant explorer. Example: ["AN"]')
        string(name: 'heapsize_mb', defaultValue: '16000',
               description: 'Heapsize in megabytes for the VCF data loader.')
        booleanParam(name: 'backup_current_data', defaultValue: false,
                     description: 'Creates a backup of the previous genomic data before replacing it with the staged data.')
        booleanParam(name: 'clean', defaultValue: false,
                     description: 'Whether to delete existing genomic data first. If false, will incrementally add staged data.')
    }

    environment {
        GIT_REPOSITORY = 'https://github.com/hms-dbmi/pic-sure-public-datasets.git'
        GIT_BRANCH = '1000Geno-Genomic-Data'
        SPARSE_CHECKOUT_PATH = 'open_access-1000Genomes'
    }

    stages {
        stage('Genomic Configuration') {
            steps {
                script {
                    def result = build job: 'Genomic Configuration', parameters: [
                        [$class: 'BooleanParameterValue', name: 'Include_Genomic_Data', value: params.Include_Genomic_Data],
                        [$class: 'BooleanParameterValue', name: 'VARIANT_EXPLORER', value: params.VARIANT_EXPLORER],
                        [$class: 'BooleanParameterValue', name: 'ENABLE_GENE_QUERY', value: params.ENABLE_GENE_QUERY],
                        [$class: 'BooleanParameterValue', name: 'ENABLE_SNP_QUERY', value: params.ENABLE_SNP_QUERY],
                        [$class: 'StringParameterValue', name: 'VARIANT_EXPLORER_TYPE', value: params.VARIANT_EXPLORER_TYPE],
                        [$class: 'StringParameterValue', name: 'EXPLORER_MAX_COUNT', value: params.EXPLORER_MAX_COUNT],
                        [$class: 'StringParameterValue', name: 'VARIANT_EXPLORER_EXCLUDE_COLUMNS', value: params.VARIANT_EXPLORER_EXCLUDE_COLUMNS]
                    ]
                }
            }
        }

        stage('Sparse Checkout 1000Genomes Data') {
            steps {
                script {
                    checkout([
                        $class: 'GitSCM',
                        branches: [[name: env.GIT_BRANCH]],
                        userRemoteConfigs: [[url: env.GIT_REPOSITORY]],
                        extensions: [
                            [$class: 'SparseCheckoutPaths', sparseCheckoutPaths: [[path: env.SPARSE_CHECKOUT_PATH]]]
                        ]
                    ])
                }
            }
        }

        stage('Stage VCF Data') {
            steps {
                script {
                    sh """
                        mkdir -p /usr/local/docker-config/vcf-load/
                        cp -r ${env.SPARSE_CHECKOUT_PATH}/* /usr/local/docker-config/vcf-load/
                        echo "1000Genomes VCF data staged to /usr/local/docker-config/vcf-load/"
                        ls -la /usr/local/docker-config/vcf-load/
                    """
                }
            }
        }

        stage('Load VCF Data') {
            steps {
                script {
                    def result = build job: 'Load VCF Data', parameters: [
                        [$class: 'StringParameterValue', name: 'partition_name', value: '1000Genomes'],
                        [$class: 'StringParameterValue', name: 'heapsize_mb', value: params.heapsize_mb]
                    ]
                }
            }
        }

        stage('Load Staged Genomic Data') {
            steps {
                script {
                    def result = build job: 'Load Staged Genomic Data', parameters: [
                        [$class: 'BooleanParameterValue', name: 'backup_current_data', value: params.backup_current_data],
                        [$class: 'BooleanParameterValue', name: 'clean', value: params.clean]
                    ]
                }
            }
        }

        stage('Restart Services') {
            steps {
                script {
                    sh "docker restart hpds || true"
                    sh "docker restart httpd || true"
                }
            }
        }
    }
}
